    if not isinstance(output, list):
        return False
    words = set(wordList)
    words.add(beginWord)
    L = len(beginWord)
    def adj(a, b):
        if len(a) != len(b):
            return False
        d = 0
        for i in range(len(a)):
            if a[i] != b[i]:
                d += 1
                if d > 1:
                    return False
        return d == 1
    # recompute the full set of shortest paths via BFS DAG
    def all_shortest():
        if endWord not in set(wordList):
            return set(), None
        from collections import deque, defaultdict
        layer = {beginWord}
        visited = {beginWord}
        parents = defaultdict(set)
        found = False
        dist = {beginWord: 0}
        while layer and not found:
            nxt = set()
            for w in layer:
                for i in range(L):
                    for c in 'abcdefghijklmnopqrstuvwxyz':
                        if c == w[i]:
                            continue
                        cand = w[:i] + c + w[i+1:]
                        if cand in words and cand not in visited:
                            nxt.add(cand)
                            parents[cand].add(w)
                            if cand == endWord:
                                found = True
            visited |= nxt
            layer = nxt
        if not found:
            return set(), None
        paths = set()
        def build(node, suffix):
            if node == beginWord:
                paths.add(tuple([beginWord] + suffix))
                return
            for p in parents[node]:
                build(p, [node] + suffix)
        build(endWord, [])
        # minimal length = len of any path
        minlen = len(next(iter(paths)))
        return paths, minlen
    correct, minlen = all_shortest()
    seen = set()
    for path in output:
        if not isinstance(path, list) or any(not isinstance(w, str) for w in path):
            return False
        if len(path) < 2 or path[0] != beginWord or path[-1] != endWord:
            return False
        if minlen is None or len(path) != minlen:
            return False
        for w in path[1:]:
            if w not in set(wordList):
                return False
        for a, b in zip(path, path[1:]):
            if not adj(a, b):
                return False
        key = tuple(path)
        if key in seen:
            return False
        seen.add(key)
    return seen == correct

