function validate(args, output) {
    const beginWord = args[0], endWord = args[1], wordList = args[2];
    if (!Array.isArray(output)) return false;
    const listSet = new Set(wordList);
    const words = new Set(wordList);
    words.add(beginWord);
    const L = beginWord.length;
    const adj = (a, b) => {
        if (a.length !== b.length) return false;
        let d = 0;
        for (let i = 0; i < a.length; i++) {
            if (a[i] !== b[i]) { d++; if (d > 1) return false; }
        }
        return d === 1;
    };
    function allShortest() {
        if (!listSet.has(endWord)) return { correct: new Set(), minlen: null };
        let layer = new Set([beginWord]);
        const visited = new Set([beginWord]);
        const parents = new Map();
        let found = false;
        while (layer.size && !found) {
            const nxt = new Set();
            for (const w of layer) {
                for (let i = 0; i < L; i++) {
                    for (let cc = 97; cc < 123; cc++) {
                        const c = String.fromCharCode(cc);
                        if (c === w[i]) continue;
                        const cand = w.slice(0, i) + c + w.slice(i + 1);
                        if (words.has(cand) && !visited.has(cand)) {
                            nxt.add(cand);
                            if (!parents.has(cand)) parents.set(cand, new Set());
                            parents.get(cand).add(w);
                            if (cand === endWord) found = true;
                        }
                    }
                }
            }
            for (const v of nxt) visited.add(v);
            layer = nxt;
        }
        if (!found) return { correct: new Set(), minlen: null };
        const paths = new Set();
        function build(node, suffix) {
            if (node === beginWord) {
                paths.add(JSON.stringify([beginWord, ...suffix]));
                return;
            }
            const ps = parents.get(node) || new Set();
            for (const p of ps) build(p, [node, ...suffix]);
        }
        build(endWord, []);
        let minlen = null;
        for (const p of paths) { minlen = JSON.parse(p).length; break; }
        return { correct: paths, minlen };
    }
    const { correct, minlen } = allShortest();
    const seen = new Set();
    for (const path of output) {
        if (!Array.isArray(path) || path.some(w => typeof w !== 'string')) return false;
        if (path.length < 2 || path[0] !== beginWord || path[path.length - 1] !== endWord) return false;
        if (minlen === null || path.length !== minlen) return false;
        for (let i = 1; i < path.length; i++) if (!listSet.has(path[i])) return false;
        for (let i = 0; i + 1 < path.length; i++) if (!adj(path[i], path[i + 1])) return false;
        const key = JSON.stringify(path);
        if (seen.has(key)) return false;
        seen.add(key);
    }
    if (seen.size !== correct.size) return false;
    for (const k of seen) if (!correct.has(k)) return false;
    return true;
}

